4456 /// Try to simplify a select instruction when its condition operand is an
4457 /// integer comparison where one operand of the compare is a constant.
4458 static Value *simplifySelectBitTest(Value *TrueVal, Value *FalseVal, Value *X,
4459                                     const APInt *Y, bool TrueWhenUnset) {
4460   const APInt *C;
