4467 
4468   // (X & Y) == 0 ? X : X & ~Y  --> X & ~Y
4469   // (X & Y) != 0 ? X : X & ~Y  --> X
4470   if (TrueVal == X && match(FalseVal, m_And(m_Specific(X), m_APInt(C))) &&
4471       *Y == ~*C)
4472     return TrueWhenUnset ? FalseVal : TrueVal;
4473 
4474   if (Y->isPowerOf2()) {
4475     // (X & Y) == 0 ? X | Y : X  --> X | Y
4476     // (X & Y) != 0 ? X | Y : X  --> X
4477     if (FalseVal == X && match(TrueVal, m_Or(m_Specific(X), m_APInt(C))) &&
4478         *Y == *C) {
4479       // We can't return the or if it has the disjoint flag.
4480       if (TrueWhenUnset && cast<PossiblyDisjointInst>(TrueVal)->isDisjoint())
4481         return nullptr;
4482       return TrueWhenUnset ? TrueVal : FalseVal;
4483     }
4484 
4485     // (X & Y) == 0 ? X : X | Y  --> X
4486     // (X & Y) != 0 ? X : X | Y  --> X | Y
4487     if (TrueVal == X && match(FalseVal, m_Or(m_Specific(X), m_APInt(C))) &&
4488         *Y == *C) {
4489       // We can't return the or if it has the disjoint flag.
4490       if (!TrueWhenUnset && cast<PossiblyDisjointInst>(FalseVal)->isDisjoint())
4491         return nullptr;
