4560   // (X <  Y) ? X : max(X, Y) --> X
4561   // (X <= Y) ? X : max(X, Y) --> X
4562   // (X >  Y) ? X : min(X, Y) --> X
4563   // (X >= Y) ? X : min(X, Y) --> X
4564   ICmpInst::Predicate InvPred = CmpInst::getInversePredicate(Pred);
4565   if (MMPred == CmpInst::getStrictPredicate(InvPred))
4566     return X;
