2061 /// Try to detect a recurrence that the value of the induction variable is
2062 /// always a power of two (or zero).
2063 static bool isPowerOfTwoRecurrence(const PHINode *PN, bool OrZero,
2064                                    unsigned Depth, SimplifyQuery &Q) {
2065   BinaryOperator *BO = nullptr;
2066   Value *Start = nullptr, *Step = nullptr;
2067   if (!matchSimpleRecurrence(PN, BO, Start, Step))
2068     return false;
2069 
2070   // Initial value must be a power of two.
2071   for (const Use &U : PN->operands()) {
2072     if (U.get() == Start) {
2073       // Initial value comes from a different BB, need to adjust context
2074       // instruction for analysis.
2075       Q.CxtI = PN->getIncomingBlock(U)->getTerminator();
2076       if (!isKnownToBeAPowerOfTwo(Start, OrZero, Depth, Q))
2077         return false;
2078     }
2079   }
2080 
2081   // Except for Mul, the induction variable must be on the left side of the
2082   // increment expression, otherwise its value can be arbitrary.
2083   if (BO->getOpcode() != Instruction::Mul && BO->getOperand(1) != Step)
2084     return false;
2085 
2086   Q.CxtI = BO->getParent()->getTerminator();
2087   switch (BO->getOpcode()) {
2088   case Instruction::Mul:
2089     // Power of two is closed under multiplication.
2090     return (OrZero || Q.IIQ.hasNoUnsignedWrap(BO) ||
2091             Q.IIQ.hasNoSignedWrap(BO)) &&
2092            isKnownToBeAPowerOfTwo(Step, OrZero, Depth, Q);
2093   case Instruction::SDiv:
2094     // Start value must not be signmask for signed division, so simply being a
2095     // power of two is not sufficient, and it has to be a constant.
2096     if (!match(Start, m_Power2()) || match(Start, m_SignMask()))
2097       return false;
2098     [[fallthrough]];
2099   case Instruction::UDiv:
2100     // Divisor must be a power of two.
2101     // If OrZero is false, cannot guarantee induction variable is non-zero after
2102     // division, same for Shr, unless it is exact division.
2103     return (OrZero || Q.IIQ.isExact(BO)) &&
2104            isKnownToBeAPowerOfTwo(Step, false, Depth, Q);
2105   case Instruction::Shl:
2106     return OrZero || Q.IIQ.hasNoUnsignedWrap(BO) || Q.IIQ.hasNoSignedWrap(BO);
2107   case Instruction::AShr:
2108     if (!match(Start, m_Power2()) || match(Start, m_SignMask()))
2109       return false;
2110     [[fallthrough]];
2111   case Instruction::LShr:
2112     return OrZero || Q.IIQ.isExact(BO);
2113   default:
2114     return false;
2115   }
2116 }
