2118 /// Return true if the given value is known to have exactly one
2119 /// bit set when defined. For vectors return true if every element is known to
2120 /// be a power of two when defined. Supports values with integer or pointer
2121 /// types and vectors of integers.
2122 bool isKnownToBeAPowerOfTwo(const Value *V, bool OrZero, unsigned Depth,
2123                             const SimplifyQuery &Q) {
2124   assert(Depth <= MaxAnalysisRecursionDepth && "Limit Search Depth");
2125 
2126   if (isa<Constant>(V))
2127     return OrZero ? match(V, m_Power2OrZero()) : match(V, m_Power2());
2128 
2129   // i1 is by definition a power of 2 or zero.
2130   if (OrZero && V->getType()->getScalarSizeInBits() == 1)
2131     return true;
2132 
2133   auto *I = dyn_cast<Instruction>(V);
2134   if (!I)
2135     return false;
2136 
2137   if (Q.CxtI && match(V, m_VScale())) {
2138     const Function *F = Q.CxtI->getFunction();
2139     // The vscale_range indicates vscale is a power-of-two.
2140     return F->hasFnAttribute(Attribute::VScaleRange);
2141   }
2142 
2143   // 1 << X is clearly a power of two if the one is not shifted off the end.  If
2144   // it is shifted off the end then the result is undefined.
2145   if (match(I, m_Shl(m_One(), m_Value())))
2146     return true;
2147 
2148   // (signmask) >>l X is clearly a power of two if the one is not shifted off
2149   // the bottom.  If it is shifted off the bottom then the result is undefined.
2150   if (match(I, m_LShr(m_SignMask(), m_Value())))
2151     return true;
2152 
2153   // The remaining tests are all recursive, so bail out if we hit the limit.
2154   if (Depth++ == MaxAnalysisRecursionDepth)
2155     return false;
2156 
2157   switch (I->getOpcode()) {
2158   case Instruction::ZExt:
2159     return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2160   case Instruction::Trunc:
2161     return OrZero && isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2162   case Instruction::Shl:
2163     if (OrZero || Q.IIQ.hasNoUnsignedWrap(I) || Q.IIQ.hasNoSignedWrap(I))
2164       return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2165     return false;
2166   case Instruction::LShr:
2167     if (OrZero || Q.IIQ.isExact(cast<BinaryOperator>(I)))
2168       return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2169     return false;
2170   case Instruction::UDiv:
2171     if (Q.IIQ.isExact(cast<BinaryOperator>(I)))
2172       return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2173     return false;
2174   case Instruction::Mul:
2175     return isKnownToBeAPowerOfTwo(I->getOperand(1), OrZero, Depth, Q) &&
2176            isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q) &&
2177            (OrZero || isKnownNonZero(I, Q, Depth));
2178   case Instruction::And:
2179     // A power of two and'd with anything is a power of two or zero.
2180     if (OrZero &&
2181         (isKnownToBeAPowerOfTwo(I->getOperand(1), /*OrZero*/ true, Depth, Q) ||
2182          isKnownToBeAPowerOfTwo(I->getOperand(0), /*OrZero*/ true, Depth, Q)))
2183       return true;
2184     // X & (-X) is always a power of two or zero.
2185     if (match(I->getOperand(0), m_Neg(m_Specific(I->getOperand(1)))) ||
